package buybetshandlers

import (
	"encoding/json"
	"errors"
	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/bets/dto"
	"socialpredict/handlers/failurereason"
	dbets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

// PlaceBetHandler returns an HTTP handler that delegates bet placement to the bets domain service.
func PlaceBetHandler(betsSvc dbets.ServiceInterface, usersSvc dusers.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		user, httpErr := authsvc.ValidateUserAndEnforcePasswordChangeGetUser(r, usersSvc)
		if httpErr != nil {
			_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAuthError(httpErr))
			return
		}

		req, decodeErr := decodePlaceBetRequest(r)
		if decodeErr != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		placedBet, err := betsSvc.Place(r.Context(), toPlaceRequest(req, user.Username))
		if err != nil {
			writePlaceBetError(w, err)
			return
		}

		writePlaceBetResponse(w, placedBet)
	}
}

func decodePlaceBetRequest(r *http.Request) (dto.PlaceBetRequest, error) {
	var req dto.PlaceBetRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return dto.PlaceBetRequest{}, errors.New("Invalid request body")
	}
	return req, nil
}

func toPlaceRequest(req dto.PlaceBetRequest, username string) dbets.PlaceRequest {
	return dbets.PlaceRequest{
		Username: username,
		MarketID: req.MarketID,
		Amount:   req.Amount,
		Outcome:  req.Outcome,
	}
}

func writePlaceBetError(w http.ResponseWriter, err error) {
	switch err {
	case dbets.ErrInvalidOutcome:
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidOutcome)
	case dbets.ErrInvalidAmount:
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
	case dbets.ErrMarketClosed:
		_ = handlers.WriteFailure(w, http.StatusConflict, handlers.ReasonMarketClosed)
	case dbets.ErrInsufficientBalance:
		_ = handlers.WriteFailure(w, http.StatusUnprocessableEntity, handlers.ReasonInsufficientBalance)
	case dmarkets.ErrMarketNotFound:
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonNotFound)
	default:
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

func writePlaceBetResponse(w http.ResponseWriter, placedBet *dbets.PlacedBet) {
	response := dto.PlaceBetResponse{
		Username: placedBet.Username,
		MarketID: placedBet.MarketID,
		Amount:   placedBet.Amount,
		Outcome:  placedBet.Outcome,
		PlacedAt: placedBet.PlacedAt,
	}

	_ = handlers.WriteResult(w, http.StatusCreated, response)
}

func reasonFromAuthError(err *authsvc.HTTPError) handlers.FailureReason {
	return failurereason.FromAuthHTTPError(err)
}

package sellbetshandlers

import (
	"encoding/json"
	"errors"
	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/bets/dto"
	"socialpredict/handlers/failurereason"
	bets "socialpredict/internal/domain/bets"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

// SellPositionHandler returns an HTTP handler that delegates sales to the bets service.
func SellPositionHandler(betsSvc bets.ServiceInterface, usersSvc dusers.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		user, httpErr := authsvc.ValidateUserAndEnforcePasswordChangeGetUser(r, usersSvc)
		if httpErr != nil {
			_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAuthError(httpErr))
			return
		}

		req, decodeErr := decodeSellRequest(r)
		if decodeErr != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		result, err := betsSvc.Sell(r.Context(), toSellRequest(req, user.Username))
		if err != nil {
			handleSellError(w, err)
			return
		}

		writeSellResponse(w, result)
	}
}

func decodeSellRequest(r *http.Request) (dto.SellBetRequest, error) {
	var req dto.SellBetRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return dto.SellBetRequest{}, errors.New("Invalid request body")
	}
	return req, nil
}

func toSellRequest(req dto.SellBetRequest, username string) bets.SellRequest {
	return bets.SellRequest{
		Username: username,
		MarketID: req.MarketID,
		Amount:   req.Amount,
		Outcome:  req.Outcome,
	}
}

func handleSellError(w http.ResponseWriter, err error) {
	if _, ok := err.(bets.ErrDustCapExceeded); ok {
		_ = handlers.WriteFailure(w, http.StatusUnprocessableEntity, handlers.ReasonDustCapExceeded)
		return
	}

	switch {
	case errors.Is(err, bets.ErrInvalidOutcome):
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidOutcome)
	case errors.Is(err, bets.ErrInvalidAmount):
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
	case errors.Is(err, bets.ErrMarketClosed):
		_ = handlers.WriteFailure(w, http.StatusConflict, handlers.ReasonMarketClosed)
	case errors.Is(err, bets.ErrNoPosition), errors.Is(err, bets.ErrInsufficientShares):
		reason := handlers.ReasonNoPosition
		if errors.Is(err, bets.ErrInsufficientShares) {
			reason = handlers.ReasonInsufficientShares
		}
		_ = handlers.WriteFailure(w, http.StatusUnprocessableEntity, reason)
	case errors.Is(err, dmarkets.ErrMarketNotFound):
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonNotFound)
	default:
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

func writeSellResponse(w http.ResponseWriter, result *bets.SellResult) {
	response := dto.SellBetResponse{
		Username:      result.Username,
		MarketID:      result.MarketID,
		SharesSold:    result.SharesSold,
		SaleValue:     result.SaleValue,
		Dust:          result.Dust,
		Outcome:       result.Outcome,
		TransactionAt: result.TransactionAt,
	}

	_ = handlers.WriteResult(w, http.StatusCreated, response)
}

func reasonFromAuthError(err *authsvc.HTTPError) handlers.FailureReason {
	return failurereason.FromAuthHTTPError(err)
}

package failurereason

import (
	"net/http"
	"strings"

	"socialpredict/handlers"
	authsvc "socialpredict/internal/service/auth"
)

// FromAuthHTTPError maps auth boundary errors onto the shared public reason
// vocabulary used by migrated handlers.
func FromAuthHTTPError(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch {
	case err.StatusCode >= http.StatusInternalServerError:
		return handlers.ReasonInternalError
	case err.StatusCode == http.StatusUnauthorized:
		return handlers.ReasonAuthenticationRequired
	case err.StatusCode == http.StatusForbidden:
		if strings.EqualFold(err.Message, "Password change required") {
			return handlers.ReasonPasswordChangeRequired
		}
		return handlers.ReasonAuthorizationDenied
	case err.StatusCode == http.StatusNotFound:
		return handlers.ReasonNotFound
	default:
		return handlers.ReasonInternalError
	}
}

// LooksLikeValidation reports whether the error string appears to describe a
// caller-fixable validation or sanitization failure rather than an internal
// server problem.
func LooksLikeValidation(err error) bool {
	if err == nil {
		return false
	}

	lower := strings.ToLower(err.Error())
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required") ||
		strings.Contains(lower, "requirement") ||
		strings.Contains(lower, "unsupported") ||
		strings.Contains(lower, "mismatch")
}

package betshandlers

import (
	"errors"
	"log"
	"net/http"
	"strconv"

	"socialpredict/handlers"
	dmarkets "socialpredict/internal/domain/markets"

	"github.com/gorilla/mux"
)

// MarketBetsHandlerWithService creates a service-injected bets handler
func MarketBetsHandlerWithService(svc dmarkets.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		marketID, err := parseMarketID(mux.Vars(r)["marketId"])
		if err != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		betsDisplayInfo, err := svc.GetMarketBets(r.Context(), marketID)
		if err != nil {
			writeMarketBetsError(w, marketID, err)
			return
		}

		if err := handlers.WriteResult(w, http.StatusOK, betsDisplayInfo); err != nil {
			log.Printf("Error encoding bets response: %v", err)
		}
	}
}

func parseMarketID(marketIDStr string) (int64, error) {
	if marketIDStr == "" {
		return 0, errors.New("Market ID is required")
	}

	marketID, err := strconv.ParseInt(marketIDStr, 10, 64)
	if err != nil {
		return 0, errors.New("Invalid market ID")
	}
	return marketID, nil
}

func writeMarketBetsError(w http.ResponseWriter, marketID int64, err error) {
	switch err {
	case dmarkets.ErrMarketNotFound:
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonNotFound)
	case dmarkets.ErrInvalidInput:
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
	default:
		log.Printf("Error getting market bets for market %d: %v", marketID, err)
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

package bets

import (
	"context"
	"time"

	"socialpredict/internal/domain/boundary"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/setup"
)

// Repository exposes the persistence layer needed by the bets domain service.
type BetWriter interface {
	Create(ctx context.Context, bet *boundary.Bet) error
}

// BetHistoryReader exposes prior-participation lookups used for buy fee rules.
type BetHistoryReader interface {
	UserHasBet(ctx context.Context, marketID uint, username string) (bool, error)
}

// Repository exposes the persistence layer needed by the bets domain service.
type Repository interface {
	BetWriter
	BetHistoryReader
}

// MarketService exposes the subset of market operations required by bets.
type MarketReader interface {
	GetMarket(ctx context.Context, id int64) (*dmarkets.Market, error)
}

// PositionReader exposes the position reads needed by share-sale flows.
type PositionReader interface {
	GetUserPositionInMarket(ctx context.Context, marketID int64, username string) (*dmarkets.UserPosition, error)
}

// MarketService exposes the subset of market operations required by bets.
type MarketService interface {
	MarketReader
	PositionReader
}

// MarketGate ensures market openness before betting operations.
type MarketGate interface {
	Open(ctx context.Context, marketID int64) (*dmarkets.Market, error)
}

// UserService exposes the subset of user operations required by bets.
type UserReader interface {
	GetUser(ctx context.Context, username string) (*dusers.User, error)
}

// TransactionRecorder exposes account mutations used by the betting ledger.
type TransactionRecorder interface {
	ApplyTransaction(ctx context.Context, username string, amount int64, transactionType string) error
}

// UserService exposes the subset of user operations required by bets.
type UserService interface {
	UserReader
	TransactionRecorder
}

// PlaceValidator allows validation rules to be extended without changing the service.
type PlaceValidator interface {
	Validate(ctx context.Context, req PlaceRequest) (string, error)
}

// SellValidator allows sell validation rules to be extended without changing the service.
type SellValidator interface {
	Validate(ctx context.Context, req SellRequest) (string, error)
}

// SaleCalculator encapsulates sale pricing and dust rules.
type SaleCalculator interface {
	Calculate(pos *dmarkets.UserPosition, sharesOwned int64, creditsRequested int64) (SaleQuote, error)
}

// FeeCalculator encapsulates buy fee calculations.
type FeeCalculator interface {
	Calculate(hasBet bool, amount int64) betFees
}

// BalanceGuard validates user balances against debt limits.
type BalanceGuard interface {
	EnsureSufficient(balance, totalCost int64) error
}

// BetLedger encapsulates persistence and user accounting for bets.
type BetLedger interface {
	ChargeAndRecord(ctx context.Context, bet *boundary.Bet, totalCost int64) error
	CreditSale(ctx context.Context, bet *boundary.Bet, saleValue int64) error
}

// Clock allows time to be mocked in tests.
type Clock interface {
	Now() time.Time
}

type serviceClock struct{}

func (serviceClock) Now() time.Time { return time.Now() }

// ServiceInterface defines the behaviour offered by the bets domain.
type ServiceInterface interface {
	Place(ctx context.Context, req PlaceRequest) (*PlacedBet, error)
	Sell(ctx context.Context, req SellRequest) (*SellResult, error)
}

// Service implements the bets domain logic.
type Service struct {
	repo    Repository
	markets MarketService
	users   UserService
	econ    *setup.EconomicConfig
	clock   Clock

	placeValidator PlaceValidator
	sellValidator  SellValidator

	marketGate     MarketGate
	fees           FeeCalculator
	balances       BalanceGuard
	ledger         BetLedger
	saleCalculator SaleCalculator
}

var (
	_ ServiceInterface = (*Service)(nil)
	_ SaleCalculator   = saleCalculator{}
)

// ServiceOption configures bets Service collaborators.
type ServiceOption func(*Service)

func defaultClock() Clock {
	return serviceClock{}
}

func defaultPlaceValidatorStrategy() PlaceValidator {
	return defaultPlaceValidator{}
}

func defaultSellValidatorStrategy() SellValidator {
	return defaultSellValidator{}
}

func defaultMarketGateStrategy(markets MarketReader, clock Clock) MarketGate {
	return marketGate{markets: markets, clock: clock}
}

func defaultFeeCalculatorStrategy(econ *setup.EconomicConfig) FeeCalculator {
	return feeCalculator{econ: econOrDefault(econ)}
}

func defaultBalanceGuardStrategy(econ *setup.EconomicConfig) BalanceGuard {
	econ = econOrDefault(econ)
	return balanceGuard{maxDebtAllowed: int64(econ.Economics.User.MaximumDebtAllowed)}
}

func defaultBetLedgerStrategy(repo BetWriter, users TransactionRecorder) BetLedger {
	return betLedger{repo: repo, users: users}
}

func defaultSaleCalculatorStrategy(econ *setup.EconomicConfig) SaleCalculator {
	econ = econOrDefault(econ)
	return saleCalculator{maxDustPerSale: int64(econ.Economics.Betting.MaxDustPerSale)}
}

func clockOrDefault(clock Clock) Clock {
	if clock == nil {
		return defaultClock()
	}
	return clock
}

func econOrDefault(econ *setup.EconomicConfig) *setup.EconomicConfig {
	if econ == nil {
		return &setup.EconomicConfig{}
	}
	return econ
}

func placeValidatorOrDefault(v PlaceValidator) PlaceValidator {
	if v == nil {
		return defaultPlaceValidatorStrategy()
	}
	return v
}

func sellValidatorOrDefault(v SellValidator) SellValidator {
	if v == nil {
		return defaultSellValidatorStrategy()
	}
	return v
}

func marketGateOrDefault(g MarketGate, markets MarketReader, clock Clock) MarketGate {
	if g == nil {
		return defaultMarketGateStrategy(markets, clock)
	}
	return g
}

func feeCalculatorOrDefault(c FeeCalculator, econ *setup.EconomicConfig) FeeCalculator {
	if c == nil {
		return defaultFeeCalculatorStrategy(econ)
	}
	return c
}

func balanceGuardOrDefault(g BalanceGuard, econ *setup.EconomicConfig) BalanceGuard {
	if g == nil {
		return defaultBalanceGuardStrategy(econ)
	}
	return g
}

func betLedgerOrDefault(l BetLedger, repo BetWriter, users TransactionRecorder) BetLedger {
	if l == nil {
		return defaultBetLedgerStrategy(repo, users)
	}
	return l
}

func saleCalculatorOrDefault(c SaleCalculator, econ *setup.EconomicConfig) SaleCalculator {
	if c == nil {
		return defaultSaleCalculatorStrategy(econ)
	}
	return c
}

// WithPlaceValidator overrides the place validator.
func WithPlaceValidator(v PlaceValidator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.placeValidator = placeValidatorOrDefault(v)
		}
	}
}

// WithSellValidator overrides the sell validator.
func WithSellValidator(v SellValidator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.sellValidator = sellValidatorOrDefault(v)
		}
	}
}

// WithMarketGate overrides the market gate.
func WithMarketGate(g MarketGate) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.marketGate = marketGateOrDefault(g, s.markets, clockOrDefault(s.clock))
		}
	}
}

// WithFeeCalculator overrides the fee calculator.
func WithFeeCalculator(c FeeCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.fees = feeCalculatorOrDefault(c, s.econ)
		}
	}
}

// WithBalanceGuard overrides the balance guard.
func WithBalanceGuard(g BalanceGuard) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.balances = balanceGuardOrDefault(g, s.econ)
		}
	}
}

// WithBetLedger overrides the bet ledger.
func WithBetLedger(l BetLedger) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.ledger = betLedgerOrDefault(l, s.repo, s.users)
		}
	}
}

// WithSaleCalculator overrides the sale calculator.
func WithSaleCalculator(c SaleCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.saleCalculator = saleCalculatorOrDefault(c, s.econ)
		}
	}
}

// WithClock overrides the service clock.
func WithClock(clock Clock) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.clock = clockOrDefault(clock)
		}
	}
}

// NewService constructs a bets service.
func NewService(repo Repository, markets MarketService, users UserService, econ *setup.EconomicConfig, clock Clock, opts ...ServiceOption) *Service {
	s := &Service{
		repo:    repo,
		markets: markets,
		users:   users,
		econ:    econOrDefault(econ),
		clock:   clockOrDefault(clock),
	}

	for _, opt := range opts {
		opt(s)
	}

package bets

import (
	"fmt"
)

// BetError exposes message-based sentinel errors behind a reusable type.
type BetError interface {
	error
	Message() string
}

type staticBetError struct {
	message string
}

func (e staticBetError) Error() string   { return e.message }
func (e staticBetError) Message() string { return e.message }

type betErrorFactory interface {
	New(message string) BetError
}

type staticBetErrorFactory struct{}

func (staticBetErrorFactory) New(message string) BetError {
	return staticBetError{message: message}
}

func newDomainError(message string) BetError {
	return staticBetErrorFactory{}.New(message)
}

var (
	// ErrInvalidOutcome is returned when the bet outcome is not recognised.
	ErrInvalidOutcome BetError = newDomainError("invalid outcome; expected YES or NO")
	// ErrInvalidAmount is returned when the bet amount is not positive.
	ErrInvalidAmount BetError = newDomainError("bet amount must be greater than zero")
	// ErrMarketClosed is returned when a bet is attempted on a closed or resolved market.
	ErrMarketClosed BetError = newDomainError("market is closed or resolved")
	// ErrInsufficientBalance indicates the user would exceed the maximum allowed debt.
	ErrInsufficientBalance BetError = newDomainError("insufficient balance for requested bet")
	// ErrNoPosition indicates the user has no position to sell.
	ErrNoPosition BetError = newDomainError("no position found for the given market and outcome")
	// ErrInsufficientShares indicates the user cannot sell the requested credits.
	ErrInsufficientShares BetError = newDomainError("not enough shares to satisfy requested sale")
)

// ErrDustCapExceeded is returned when a sell transaction would generate dust above the configured cap.
type ErrDustCapExceeded struct {
	Cap       int64
	Requested int64
}

func (e ErrDustCapExceeded) Error() string {
	return dustCapExceededMessage(e.Cap, e.Requested)
}

func (e ErrDustCapExceeded) Is(target error) bool {
	switch target.(type) {
	case ErrDustCapExceeded, *ErrDustCapExceeded:
		return true
	default:
		return false
	}
}

func newDustCapExceeded(cap, requested int64) ErrDustCapExceeded {
	return ErrDustCapExceeded{
		Cap:       cap,
		Requested: requested,
	}
}

func dustCapExceededMessage(cap, requested int64) string {
	return fmt.Sprintf("dust cap exceeded: would generate %d dust points (cap: %d)", requested, cap)
}

