func TestMarketBetsHandlerWithService(t *testing.T) {
	now := time.Date(2025, 1, 2, 3, 4, 5, 0, time.UTC)

	tests := []struct {
		name           string
		method         string
		vars           map[string]string
		stub           marketServiceStub
