func TestHandlerCreateMarketFailureEnvelope(t *testing.T) {
	body := bytes.NewBufferString(`{"questionTitle":"Question?","outcomeType":"BINARY","resolutionDateTime":"2035-01-02T03:04:05Z"}`)

