package auth

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"os"
	"socialpredict/handlers"

	"socialpredict/internal/domain/boundary"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/security"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v4"
)

// login and validation stuff
// getJWTKey returns the JWT signing key, checking environment variable at runtime
func getJWTKey() []byte {
	return []byte(strings.TrimSpace(os.Getenv("JWT_SIGNING_KEY")))
}

// LoginUserRepository exposes only the user lookup required for login.
type LoginUserRepository interface {
	FindAuthenticatedUser(ctx context.Context, username string) (*boundary.AuthenticatedUser, error)
}

// UserClaims represents the expected structure of the JWT claims
type UserClaims struct {
	Username string `json:"username"`
	jwt.StandardClaims
}

type loginResponse struct {
	Token              string `json:"token"`
	Username           string `json:"username"`
	UserType           string `json:"usertype"`
	MustChangePassword bool   `json:"mustChangePassword"`
}

func LoginHandler(users LoginUserRepository) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = writeLoginFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		securityService := security.NewSecurityService()

		req, err := decodeLoginRequest(r)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		req, err = validateAndSanitizeLogin(securityService, req)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		if users == nil {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		user, loginErr := authenticateUser(r.Context(), users, req)
		if loginErr != nil {
			_ = writeLoginFailure(w, loginErr.statusCode, loginFailureReason(loginErr.statusCode))
			return
		}

		jwtKey := getJWTKey()
		if len(jwtKey) == 0 {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		tokenString, err := generateJWT(user.Username, jwtKey)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		_ = writeLoginResponse(w, user, tokenString)
	}
}

type loginRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
	Password string `json:"password" validate:"required,min=1"`
}

func decodeLoginRequest(r *http.Request) (loginRequest, error) {
	var req loginRequest
	decoder := json.NewDecoder(io.LimitReader(r.Body, 1<<20))
	decoder.DisallowUnknownFields()
	if err := decoder.Decode(&req); err != nil {
		return loginRequest{}, fmt.Errorf("error reading request body")
	}
	if err := decoder.Decode(&struct{}{}); err != io.EOF {
		return loginRequest{}, fmt.Errorf("error reading request body")
	}
	return req, nil
}

func validateAndSanitizeLogin(securityService *security.SecurityService, req loginRequest) (loginRequest, error) {
	sanitizedUsername, err := securityService.Sanitizer.SanitizeUsername(req.Username)
	if err != nil {
		return req, fmt.Errorf("invalid input")
	}
	req.Username = sanitizedUsername

	if err := securityService.Validator.ValidateStruct(req); err != nil {
		return req, fmt.Errorf("invalid input")
	}

	return req, nil
}

type loginError struct {
	statusCode int
}

func authenticateUser(ctx context.Context, users LoginUserRepository, req loginRequest) (boundary.AuthenticatedUser, *loginError) {
	if users == nil {
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusInternalServerError}
	}

	user, err := findUserByUsername(ctx, users, req.Username)
	if err != nil {
		if errors.Is(err, dusers.ErrUserNotFound) {
			return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusUnauthorized}
		}
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusInternalServerError}
	}

	if !user.CheckPasswordHash(req.Password) {
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusUnauthorized}
	}

	return user, nil
}

func findUserByUsername(ctx context.Context, users LoginUserRepository, username string) (boundary.AuthenticatedUser, error) {
	if users == nil {
		return boundary.AuthenticatedUser{}, fmt.Errorf("database connection is not initialized")
	}

	user, err := users.FindAuthenticatedUser(ctx, username)
	if err != nil {
		return boundary.AuthenticatedUser{}, err
	}
	if user == nil {
		return boundary.AuthenticatedUser{}, dusers.ErrUserNotFound
	}
	return *user, nil
}

func generateJWT(username string, jwtKey []byte) (string, error) {
	if len(jwtKey) == 0 {
		return "", fmt.Errorf("missing JWT signing key")
	}

	claims := &UserClaims{
		Username: username,
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: time.Now().UTC().Add(24 * time.Hour).Unix(),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString(jwtKey)
}

func writeLoginResponse(w http.ResponseWriter, user boundary.AuthenticatedUser, tokenString string) error {
	return handlers.WriteResult(w, http.StatusOK, loginResponse{
		Token:              tokenString,
		Username:           user.Username,
		UserType:           user.UserType,
		MustChangePassword: user.MustChangePassword,
	})
}

func writeLoginFailure(w http.ResponseWriter, statusCode int, reason handlers.FailureReason) error {
	return handlers.WriteFailure(w, statusCode, reason)
}

func loginFailureReason(statusCode int) handlers.FailureReason {
	switch statusCode {
	case http.StatusBadRequest:
		return handlers.ReasonInvalidRequest
	case http.StatusUnauthorized:
		return handlers.ReasonInvalidCredentials
	default:
		return handlers.ReasonInternalError
	}
}

package security

import (
	"net/http"
)

// SecurityService provides a comprehensive security layer for the application
type SecurityService struct {
	Sanitizer   *Sanitizer
	Validator   *Validator
	RateManager *RateLimitManager
	Headers     SecurityHeaders
}

// NewSecurityService creates a new security service with default configurations
func NewSecurityService() *SecurityService {
	return &SecurityService{
		Sanitizer:   NewSanitizer(),
		Validator:   NewValidator(),
		RateManager: NewRateLimitManager(),
		Headers:     DefaultSecurityHeaders(),
	}
}

// NewCustomSecurityService creates a security service with custom rate limiting configuration
func NewCustomSecurityService(rateLimitConfig RateLimitConfig) *SecurityService {
	return &SecurityService{
		Sanitizer:   NewSanitizer(),
		Validator:   NewValidator(),
		RateManager: NewCustomRateLimitManager(rateLimitConfig),
		Headers:     DefaultSecurityHeaders(),
	}
}

// SecurityMiddleware combines all security middleware into a single middleware stack
func (s *SecurityService) SecurityMiddleware() func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		// Apply middleware in order: headers first, then rate limiting, then the handler
		return SecurityHeadersMiddleware(s.Headers)(
			s.RateManager.GetGeneralMiddleware()(next),
		)
	}
}

// LoginSecurityMiddleware provides enhanced security for login endpoints
func (s *SecurityService) LoginSecurityMiddleware() func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		// Apply security headers and stricter rate limiting for login
		return SecurityHeadersMiddleware(s.Headers)(
			s.RateManager.GetLoginMiddleware()(next),
		)
	}
}

// ValidateAndSanitizeUserInput validates and sanitizes user registration/update data
func (s *SecurityService) ValidateAndSanitizeUserInput(input UserInput) (*SanitizedUserInput, error) {
	// First validate the input structure
	if err := s.Validator.ValidateStruct(input); err != nil {
		return nil, err
	}

	// Then sanitize each field
	sanitizedUsername, err := s.Sanitizer.SanitizeUsername(input.Username)
	if err != nil {
		return nil, err
	}

	sanitizedDisplayName, err := s.Sanitizer.SanitizeDisplayName(input.DisplayName)
	if err != nil {
		return nil, err
	}

	sanitizedDescription, err := s.Sanitizer.SanitizeDescription(input.Description)
	if err != nil {
		return nil, err
	}

	sanitizedEmoji, err := s.Sanitizer.SanitizeEmoji(input.PersonalEmoji)
	if err != nil {
		return nil, err
	}

	sanitizedLinks, err := s.sanitizePersonalLinks(input)
	if err != nil {
		return nil, err
	}

	if err := s.validateOptionalPassword(input.Password); err != nil {
		return nil, err
	}

	return &SanitizedUserInput{
		Username:      sanitizedUsername,
		DisplayName:   sanitizedDisplayName,
		Description:   sanitizedDescription,
		PersonalEmoji: sanitizedEmoji,
		PersonalLink1: sanitizedLinks[0],
		PersonalLink2: sanitizedLinks[1],
		PersonalLink3: sanitizedLinks[2],
		PersonalLink4: sanitizedLinks[3],
		Password:      input.Password, // Keep original for hashing
	}, nil
}

func (s *SecurityService) sanitizePersonalLinks(input UserInput) ([4]string, error) {
	var sanitizedLinks [4]string
	links := [4]string{input.PersonalLink1, input.PersonalLink2, input.PersonalLink3, input.PersonalLink4}
	for i, link := range links {
		sanitized, err := s.Sanitizer.SanitizePersonalLink(link)
		if err != nil {
			return sanitizedLinks, err
		}
		sanitizedLinks[i] = sanitized
	}
	return sanitizedLinks, nil
}

func (s *SecurityService) validateOptionalPassword(password string) error {
	if password == "" {
		return nil
	}
	_, err := s.Sanitizer.SanitizePassword(password)
	return err
}

// ValidateAndSanitizeMarketInput validates and sanitizes market creation data
func (s *SecurityService) ValidateAndSanitizeMarketInput(input MarketInput) (*SanitizedMarketInput, error) {
	// First validate the input structure
	if err := s.Validator.ValidateStruct(input); err != nil {
		return nil, err
	}

	// Sanitize the market title
	sanitizedTitle, err := s.Sanitizer.SanitizeMarketTitle(input.Title)
	if err != nil {
		return nil, err
	}

	// Sanitize the description
	sanitizedDescription, err := s.Sanitizer.SanitizeDescription(input.Description)
	if err != nil {
		return nil, err
	}

	return &SanitizedMarketInput{
		Title:       sanitizedTitle,
		Description: sanitizedDescription,
		EndTime:     input.EndTime,
	}, nil
}

// Input structures for validation
